//! Recon -> third-eye prior INPUT plumbing: load a per-object MATERIAL / MASS / INERTIA prior set
//! from an external JSON file and key it by track id, so third-eye's object intelligence can GROUND
//! its physics with real material-weighted values instead of the relative `DENSITY_GUESS = 1.0`.
//!
//! This is the recon-side half of the bidirectional loop. The single-image reconstruction
//! (`apps/monster-studio/scripts/object-intel.mjs deriveObjectIntel`) computes, per object, a ranked
//! MATERIAL, a MASS (material density × solid voxel volume) and an INERTIA TENSOR from the real
//! reconstructed geometry. That JSON is handed to third-eye via `--object-priors priors.json`; here we
//! parse it into [`ObjectPrior`]s keyed by track id (or matched heuristically by index/order when the
//! recon has no track id).
//!
//! JSON FORMAT (a flat object mapping track-id -> prior, OR an array of priors carrying an `id`):
//!
//! ```json
//! {
//!   "1": { "material": "plastic",      "density": 1.2, "inertia": 0.0008, "scale_ref_cm": 9.5 },
//!   "2": { "material": "metal (steel)", "density": 3.0 }
//! }
//! ```
//!
//! Only `density` is load-bearing for the material-weighted mass ratio; `material` picks the
//! restitution prior; `inertia` and `scale_ref_cm` are optional. Unknown ids are simply absent (the
//! object falls back to the relative equal-density profile). The parser is dependency-free (the crate
//! pulls in no serde) and tolerant: it skips fields it does not recognise.
//!
//! HONEST: `density` here is a RELATIVE weight (g/cm³ in the recon table, but only the ratio between
//! objects is grounded — the recon volume is in normalised units, no absolute SI). See `ObjectPrior`.

use crate::object_intel::{MaterialKind, ObjectPrior};
use std::collections::HashMap;

/// A loaded set of per-track recon priors. Lookup is by track id; a missing id means "no prior" (the
/// relative equal-density fallback). Also keeps the priors in declaration order so a recon set without
/// track ids can be matched POSITIONALLY against the scene's confirmed tracks.
#[derive(Debug, Clone, Default)]
pub struct PriorSet {
    by_id: HashMap<u64, ObjectPrior>,
    /// Priors in the order they were declared (for positional matching when ids do not line up).
    ordered: Vec<(Option<u64>, ObjectPrior)>,
}

impl PriorSet {
    /// The prior for a track id, if one was supplied.
    pub fn get(&self, id: u64) -> Option<&ObjectPrior> {
        self.by_id.get(&id)
    }

    /// Number of priors loaded.
    pub fn len(&self) -> usize {
        self.ordered.len()
    }

    pub fn is_empty(&self) -> bool {
        self.ordered.is_empty()
    }

    /// All priors in declaration order (id may be None when the recon gave no track id).
    pub fn ordered(&self) -> &[(Option<u64>, ObjectPrior)] {
        &self.ordered
    }

    /// True if ANY scale reference is present (so absolute SI MAY be reported; otherwise abstain).
    pub fn has_scale_ref(&self) -> bool {
        self.ordered.iter().any(|(_, p)| p.scale_ref_cm.is_some())
    }

    /// Parse a PriorSet from JSON text. Accepts either an object keyed by id-string or an array of
    /// prior objects each carrying an `id`. Returns an error string on a malformed top level.
    pub fn from_json(text: &str) -> Result<PriorSet, String> {
        let mut p = Parser::new(text);
        p.skip_ws();
        let mut set = PriorSet::default();
        match p.peek() {
            Some('{') => {
                p.expect('{')?;
                p.skip_ws();
                if p.peek() == Some('}') {
                    p.next();
                    return Ok(set);
                }
                loop {
                    p.skip_ws();
                    let key = p.parse_string()?;
                    p.skip_ws();
                    p.expect(':')?;
                    p.skip_ws();
                    let prior = parse_prior_obj(&mut p)?;
                    let id = key.parse::<u64>().ok();
                    if let Some(idv) = id {
                        set.by_id.insert(idv, prior);
                    }
                    set.ordered.push((id, prior));
                    p.skip_ws();
                    match p.next() {
                        Some(',') => continue,
                        Some('}') => break,
                        _ => return Err("expected ',' or '}' in priors object".into()),
                    }
                }
            }
            Some('[') => {
                p.expect('[')?;
                p.skip_ws();
                if p.peek() == Some(']') {
                    p.next();
                    return Ok(set);
                }
                loop {
                    p.skip_ws();
                    let (id, prior) = parse_prior_with_id(&mut p)?;
                    if let Some(idv) = id {
                        set.by_id.insert(idv, prior);
                    }
                    set.ordered.push((id, prior));
                    p.skip_ws();
                    match p.next() {
                        Some(',') => continue,
                        Some(']') => break,
                        _ => return Err("expected ',' or ']' in priors array".into()),
                    }
                }
            }
            _ => return Err("priors JSON must be an object or array".into()),
        }
        Ok(set)
    }

    /// Load a PriorSet from a JSON file path. Native-only: wasm callers pass the priors JSON
    /// string straight to [`PriorSet::from_json`] (the host already read the file).
    #[cfg(not(target_arch = "wasm32"))]
    pub fn load(path: &str) -> Result<PriorSet, String> {
        let text = std::fs::read_to_string(path).map_err(|e| format!("read {path}: {e}"))?;
        PriorSet::from_json(&text)
    }
}

/// Parse one prior object `{ "material": ..., "density": ..., "inertia": ..., "scale_ref_cm": ... }`.
/// An `id` field, if present, is ignored here (handled by `parse_prior_with_id`).
fn parse_prior_obj(p: &mut Parser) -> Result<ObjectPrior, String> {
    let (_, prior) = parse_prior_with_id(p)?;
    Ok(prior)
}

/// Parse one prior object and pull out an optional `id` field (for the array form).
fn parse_prior_with_id(p: &mut Parser) -> Result<(Option<u64>, ObjectPrior), String> {
    p.skip_ws();
    p.expect('{')?;
    let mut density = 0.0f32;
    let mut material = MaterialKind::Unknown;
    let mut inertia: Option<f32> = None;
    let mut scale_ref_cm: Option<f32> = None;
    let mut id: Option<u64> = None;
    p.skip_ws();
    if p.peek() == Some('}') {
        p.next();
        return Ok((id, ObjectPrior { density, material, inertia, scale_ref_cm }));
    }
    loop {
        p.skip_ws();
        let field = p.parse_string()?;
        p.skip_ws();
        p.expect(':')?;
        p.skip_ws();
        match field.as_str() {
            "density" => density = p.parse_number()? as f32,
            "material" => material = MaterialKind::from_name(&p.parse_string()?),
            "inertia" | "inertia_spin" => {
                let v = p.parse_number()? as f32;
                if v > 0.0 {
                    inertia = Some(v);
                }
            }
            "scale_ref_cm" | "scaleRefCm" => {
                let v = p.parse_number()? as f32;
                if v > 0.0 {
                    scale_ref_cm = Some(v);
                }
            }
            "id" | "track" | "trackId" => {
                // id may be a number or a string-number.
                p.skip_ws();
                if p.peek() == Some('"') {
                    id = p.parse_string()?.parse::<u64>().ok();
                } else {
                    id = Some(p.parse_number()? as u64);
                }
            }
            _ => p.skip_value()?, // unrecognised field: skip its value (mass, name, etc.)
        }
        p.skip_ws();
        match p.next() {
            Some(',') => continue,
            Some('}') => break,
            _ => return Err(format!("expected ',' or '}}' after field '{field}'")),
        }
    }
    Ok((id, ObjectPrior { density, material, inertia, scale_ref_cm }))
}

/// A tiny, dependency-free JSON scanner — only the subset the priors format needs (objects, arrays,
/// strings, numbers, booleans, null). NOT a general JSON library; tolerant skip of unknown values.
struct Parser<'a> {
    chars: Vec<char>,
    i: usize,
    _src: &'a str,
}

impl<'a> Parser<'a> {
    fn new(src: &'a str) -> Self {
        Parser { chars: src.chars().collect(), i: 0, _src: src }
    }
    fn peek(&self) -> Option<char> {
        self.chars.get(self.i).copied()
    }
    fn next(&mut self) -> Option<char> {
        let c = self.chars.get(self.i).copied();
        if c.is_some() {
            self.i += 1;
        }
        c
    }
    fn skip_ws(&mut self) {
        while let Some(c) = self.peek() {
            if c.is_whitespace() {
                self.i += 1;
            } else {
                break;
            }
        }
    }
    fn expect(&mut self, c: char) -> Result<(), String> {
        match self.next() {
            Some(x) if x == c => Ok(()),
            other => Err(format!("expected '{c}', got {other:?}")),
        }
    }
    fn parse_string(&mut self) -> Result<String, String> {
        self.skip_ws();
        self.expect('"')?;
        let mut out = String::new();
        while let Some(c) = self.next() {
            match c {
                '"' => return Ok(out),
                '\\' => match self.next() {
                    Some('n') => out.push('\n'),
                    Some('t') => out.push('\t'),
                    Some('r') => out.push('\r'),
                    Some('"') => out.push('"'),
                    Some('\\') => out.push('\\'),
                    Some('/') => out.push('/'),
                    Some(other) => out.push(other),
                    None => return Err("unterminated escape in string".into()),
                },
                _ => out.push(c),
            }
        }
        Err("unterminated string".into())
    }
    fn parse_number(&mut self) -> Result<f64, String> {
        self.skip_ws();
        let start = self.i;
        while let Some(c) = self.peek() {
            if c.is_ascii_digit() || matches!(c, '-' | '+' | '.' | 'e' | 'E') {
                self.i += 1;
            } else {
                break;
            }
        }
        let s: String = self.chars[start..self.i].iter().collect();
        s.parse::<f64>().map_err(|_| format!("bad number '{s}'"))
    }
    /// Skip an arbitrary JSON value (string / number / object / array / true / false / null) without
    /// interpreting it — used to ignore unrecognised prior fields.
    fn skip_value(&mut self) -> Result<(), String> {
        self.skip_ws();
        match self.peek() {
            Some('"') => {
                self.parse_string()?;
                Ok(())
            }
            Some('{') => {
                self.next();
                self.skip_ws();
                if self.peek() == Some('}') {
                    self.next();
                    return Ok(());
                }
                loop {
                    self.parse_string()?;
                    self.skip_ws();
                    self.expect(':')?;
                    self.skip_value()?;
                    self.skip_ws();
                    match self.next() {
                        Some(',') => continue,
                        Some('}') => break,
                        _ => return Err("bad object in skip".into()),
                    }
                }
                Ok(())
            }
            Some('[') => {
                self.next();
                self.skip_ws();
                if self.peek() == Some(']') {
                    self.next();
                    return Ok(());
                }
                loop {
                    self.skip_value()?;
                    self.skip_ws();
                    match self.next() {
                        Some(',') => continue,
                        Some(']') => break,
                        _ => return Err("bad array in skip".into()),
                    }
                }
                Ok(())
            }
            Some(c) if c.is_ascii_digit() || c == '-' => {
                self.parse_number()?;
                Ok(())
            }
            Some('t') | Some('f') | Some('n') => {
                // true / false / null — consume word chars.
                while let Some(c) = self.peek() {
                    if c.is_ascii_alphabetic() {
                        self.i += 1;
                    } else {
                        break;
                    }
                }
                Ok(())
            }
            other => Err(format!("unexpected value start {other:?}")),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parses_object_keyed_by_id() {
        let json = r#"{
            "1": { "material": "plastic", "density": 1.2, "inertia": 0.0008, "scale_ref_cm": 9.5 },
            "2": { "material": "metal (steel)", "density": 3.0 }
        }"#;
        let set = PriorSet::from_json(json).expect("parse");
        assert_eq!(set.len(), 2);
        let a = set.get(1).expect("id 1");
        assert!((a.density - 1.2).abs() < 1e-6);
        assert_eq!(a.material, MaterialKind::Plastic);
        assert_eq!(a.inertia, Some(0.0008));
        assert_eq!(a.scale_ref_cm, Some(9.5));
        let b = set.get(2).expect("id 2");
        assert!((b.density - 3.0).abs() < 1e-6);
        assert_eq!(b.material, MaterialKind::Metal);
        assert_eq!(b.inertia, None);
        assert!(set.has_scale_ref());
    }

    #[test]
    fn parses_array_with_ids_and_skips_unknown_fields() {
        let json = r#"[
            { "id": 3, "material": "rubber", "density": 1.2, "mass": 42, "name": "ball" },
            { "id": "7", "material": "wood", "density": 0.7 }
        ]"#;
        let set = PriorSet::from_json(json).expect("parse");
        assert_eq!(set.len(), 2);
        assert_eq!(set.get(3).unwrap().material, MaterialKind::Rubber);
        assert_eq!(set.get(7).unwrap().material, MaterialKind::Soft);
        assert!(!set.has_scale_ref());
    }

    #[test]
    fn empty_object_is_empty_set() {
        let set = PriorSet::from_json("{}").expect("parse");
        assert!(set.is_empty());
        assert!(set.get(1).is_none());
    }

    #[test]
    fn material_name_mapping_is_tolerant() {
        assert_eq!(MaterialKind::from_name("ceramic / porcelain"), MaterialKind::Ceramic);
        assert_eq!(MaterialKind::from_name("Aluminum"), MaterialKind::Metal);
        assert_eq!(MaterialKind::from_name("paper / cardboard"), MaterialKind::Soft);
        assert_eq!(MaterialKind::from_name("mystery goo"), MaterialKind::Unknown);
    }
}
